9817	\begin{lemma}[Quasi-coherence of an iso-pushforward reduces to its slices]
9818	  \label{lem:pushforward_iso_qcoh_of_slice_qcoh}
9819	  \lean{AlgebraicGeometry.pushforward_iso_qcoh_of_slice_qcoh,
9820	    AlgebraicGeometry.coversTop_preimage_of_iso}
9821	  \uses{lem:isQuasicoherent_of_coversTop_mathlib, lem:nonempty_quasicoherentData_mathlib}
9822	  Let \(\varphi : X \cong Y\) be an isomorphism of schemes,
9823	  \(\Phi = \operatorname{pushforwardEquivOfIso}\varphi\) the induced equivalence, \(H :
9824	  X.\mathrm{Modules}\), and \((U_i)_{i \in I}\) a family of opens covering \(X\). Then quasi-coherence
9825	  of the pushforward \(\Phi.\mathrm{functor}.\mathrm{obj}\, H\) reduces to quasi-coherence of its
9826	  restrictions to the preimage-transported cover: if for every \(i\) the slice
9827	  \[
9828	    \bigl(\Phi.\mathrm{functor}.\mathrm{obj}\, H\bigr).\operatorname{over}
9829	      \bigl(\varphi.\mathrm{inv}^{-1}\,U_i\bigr)
9830	  \]
9831	  is quasi-coherent, then \(\Phi.\mathrm{functor}.\mathrm{obj}\, H\) is quasi-coherent.
9832	\end{lemma}
9833	\begin{proof}
9834	  \uses{lem:isQuasicoherent_of_coversTop_mathlib, lem:nonempty_quasicoherentData_mathlib}
9835	  The preimages \(V_i = \varphi.\mathrm{inv}^{-1}\,U_i\) again cover \(Y\): the underlying map of
9836	  \(\varphi.\mathrm{inv}\) is a homeomorphism, so a covering family of \(X\) pulls back to a covering
9837	  family of \(Y\). Concretely, membership in \(\operatorname{Opens.grothendieckTopology}\) is preserved
9838	  under the iso by transporting the covering sieve \(\operatorname{Sieve.ofObjects}\) along
9839	  \(\varphi\) (the cover-transport step). With \((V_i)\) covering \(Y\) and each slice
9840	  \((\Phi.\mathrm{functor}.\mathrm{obj}\, H).\operatorname{over} V_i\) quasi-coherent by hypothesis,
9841	  quasi-coherence of \(\Phi.\mathrm{functor}.\mathrm{obj}\, H\) follows from the cover criterion
9842	  (Lemma~\ref{lem:isQuasicoherent_of_coversTop_mathlib}); the family \((U_i)\) is supplied by the
9843	  quasi-coherence datum of \(H\) (Lemma~\ref{lem:nonempty_quasicoherentData_mathlib}).
9844	\end{proof}
